import { useEffect, useState, useCallback, useMemo } from 'react';
import { useTable, useSortBy } from 'react-table';
import { getAllStock, addStock, removeStock, transferStock, getEntrepots, getProduits } from '../services/stockApi';
import { Plus, Minus, ArrowRightLeft, Search, Filter } from 'lucide-react';
import Modal from '../components/Modal';
import Spinner from '../components/Spinner';
import toast from 'react-hot-toast';

// ── Formulaire générique ─────────────────────────────────────
function StockForm({ produits, entrepots, onSubmit, type }) {
  const [form, setForm] = useState({
    productId: '', warehouseId: '', fromWarehouseId: '', toWarehouseId: '',
    quantity: '', note: '',
  });
  const [loading, setLoading] = useState(false);

  const set = (k, v) => setForm(prev => ({ ...prev, [k]: v }));

  const handleSubmit = async () => {
    if (!form.productId || !form.quantity) return toast.error('Champs obligatoires manquants');
    setLoading(true);
    try {
      const payload = {
        productId: Number(form.productId),
        quantity:  Number(form.quantity),
        note:      form.note || null,
      };
      if (type === 'add')      payload.warehouseId    = Number(form.warehouseId);
      if (type === 'remove')   payload.warehouseId    = Number(form.warehouseId);
      if (type === 'transfer') {
        payload.fromWarehouseId = Number(form.fromWarehouseId);
        payload.toWarehouseId   = Number(form.toWarehouseId);
      }
      await onSubmit(payload);
    } finally { setLoading(false); }
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
      <div className="form-group">
        <label>Produit *</label>
        <select value={form.productId} onChange={e => set('productId', e.target.value)}>
          <option value="">— Sélectionner —</option>
          {produits.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
        </select>
      </div>

      {(type === 'add' || type === 'remove') && (
        <div className="form-group">
          <label>Entrepôt *</label>
          <select value={form.warehouseId} onChange={e => set('warehouseId', e.target.value)}>
            <option value="">— Sélectionner —</option>
            {entrepots.map(e => <option key={e.id} value={e.id}>{e.name}</option>)}
          </select>
        </div>
      )}

      {type === 'transfer' && (
        <div className="form-grid">
          <div className="form-group">
            <label>Entrepôt source *</label>
            <select value={form.fromWarehouseId} onChange={e => set('fromWarehouseId', e.target.value)}>
              <option value="">— Source —</option>
              {entrepots.map(e => <option key={e.id} value={e.id}>{e.name}</option>)}
            </select>
          </div>
          <div className="form-group">
            <label>Entrepôt destination *</label>
            <select value={form.toWarehouseId} onChange={e => set('toWarehouseId', e.target.value)}>
              <option value="">— Destination —</option>
              {entrepots.map(e => <option key={e.id} value={e.id}>{e.name}</option>)}
            </select>
          </div>
        </div>
      )}

      <div className="form-group">
        <label>Quantité *</label>
        <input type="number" min="1" placeholder="0"
               value={form.quantity} onChange={e => set('quantity', e.target.value)} />
      </div>
      <div className="form-group">
        <label>Note (optionnel)</label>
        <input type="text" placeholder="Raison, référence…"
               value={form.note} onChange={e => set('note', e.target.value)} />
      </div>

      <button
        className={`btn ${type === 'add' ? 'btn-success' : type === 'remove' ? 'btn-danger' : 'btn-primary'}`}
        style={{ width: '100%', justifyContent: 'center', marginTop: 4 }}
        onClick={handleSubmit}
        disabled={loading}
      >
        {loading ? 'Traitement…' : type === 'add' ? 'Ajouter' : type === 'remove' ? 'Retirer' : 'Transférer'}
      </button>
    </div>
  );
}

// ── Page principale ──────────────────────────────────────────
export default function StockList() {
  const [stocks,    setStocks]    = useState([]);
  const [produits,  setProduits]  = useState([]);
  const [entrepots, setEntrepots] = useState([]);
  const [loading,   setLoading]   = useState(true);
  const [modal,     setModal]     = useState(null); // 'add' | 'remove' | 'transfer'
  const [search,    setSearch]    = useState('');
  const [filterWH,  setFilterWH]  = useState('');

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const [s, p, e] = await Promise.all([
        getAllStock(filterWH || undefined),
        getProduits(),
        getEntrepots(),
      ]);
      setStocks(s.data);
      setProduits(p.data);
      setEntrepots(e.data);
    } catch { toast.error('Erreur de chargement'); }
    finally { setLoading(false); }
  }, [filterWH]);

  useEffect(() => { load(); }, [load]);

  const filtered = stocks.filter(s =>
    s.productName.toLowerCase().includes(search.toLowerCase()) ||
    s.warehouseName.toLowerCase().includes(search.toLowerCase())
  );

  const columns = useMemo(() => [
    { Header: '#', accessor: (_, i) => i + 1, id: 'index', disableSortBy: true },
    { Header: 'Produit', accessor: 'productName' },
    { Header: 'Prix unitaire', accessor: d => d.productPrice?.toFixed(2) + ' €', id: 'price' },
    { Header: 'Entrepôt', accessor: 'warehouseName' },
    { Header: 'Localisation', accessor: 'warehouseLocation' },
    { Header: 'Quantité', accessor: 'quantity', Cell: ({ value }) => quantityCell(value) },
    { Header: 'Mis à jour', accessor: d => d.updatedAt ? new Date(d.updatedAt).toLocaleDateString('fr-FR') : '—', id: 'updatedAt' },
  ], []);

  const table = useTable({ columns, data: filtered }, useSortBy);
  const { getTableProps, getTableBodyProps, headerGroups, rows, prepareRow } = table;

  const handleOp = (fn, successMsg) => async (payload) => {
    try {
      await fn(payload);
      toast.success(successMsg);
      setModal(null);
      load();
    } catch (e) { toast.error(e.message); }
  };

  const quantityCell = quantity => {
    const style = quantity < 10
      ? 'bg-rose-500/20 text-rose-300'
      : quantity < 30
      ? 'bg-amber-500/20 text-amber-200'
      : 'bg-emerald-500/20 text-emerald-200';
    return (
      <span className={`inline-flex items-center gap-1 px-2 py-1 rounded-full text-xs font-semibold ${style}`}>
        {quantity}
        {quantity < 10 && <span className="text-rose-300">⚠</span>}
      </span>
    );
  };

  return (
    <div className="page">
      <div className="page-header">
        <div>
          <h2>Stocks</h2>
          <p>Liste complète des stocks par produit et entrepôt</p>
        </div>
        <div style={{ display: 'flex', gap: 10 }}>
          <button className="btn btn-success"  onClick={() => setModal('add')}>
            <Plus size={15} /> Ajouter
          </button>
          <button className="btn btn-danger"   onClick={() => setModal('remove')}>
            <Minus size={15} /> Retirer
          </button>
          <button className="btn btn-primary"  onClick={() => setModal('transfer')}>
            <ArrowRightLeft size={15} /> Transférer
          </button>
        </div>
      </div>

      <div className="toolbar">
        <div className="search-box">
          <Search />
          <input placeholder="Rechercher produit ou entrepôt…"
                 value={search} onChange={e => setSearch(e.target.value)} />
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <Filter size={15} style={{ color: 'var(--text-muted)' }} />
          <select value={filterWH} onChange={e => setFilterWH(e.target.value)}
                  style={{ background: 'var(--bg-2)', border: '1px solid var(--border)',
                           color: 'var(--text)', padding: '8px 12px', borderRadius: 8, fontSize: 13.5 }}>
            <option value="">Tous les entrepôts</option>
            {entrepots.map(e => <option key={e.id} value={e.id}>{e.name}</option>)}
          </select>
        </div>
      </div>

      {loading ? <Spinner /> : (
        <div className="overflow-x-auto rounded-2xl border border-slate-700 bg-slate-900 shadow-xl">
          <table {...getTableProps()} className="min-w-full divide-y divide-slate-700">
            <thead className="bg-slate-800 text-xs uppercase tracking-wide text-slate-400">
              {headerGroups.map(headerGroup => (
                <tr {...headerGroup.getHeaderGroupProps()}>
                  {headerGroup.headers.map(column => (
                    <th
                      {...column.getHeaderProps(column.getSortByToggleProps())}
                      className="px-4 py-3 text-left"
                    >
                      {column.render('Header')}
                      <span>
                        {column.isSorted ? (column.isSortedDesc ? ' ↓' : ' ↑') : ''}
                      </span>
                    </th>
                  ))}
                </tr>
              ))}
            </thead>
            <tbody {...getTableBodyProps()} className="divide-y divide-slate-700 bg-slate-900 text-sm text-slate-100">
              {rows.length === 0 ? (
                <tr>
                  <td colSpan={7} className="px-4 py-8 text-center text-slate-400">Aucun résultat</td>
                </tr>
              ) : rows.map(row => {
                prepareRow(row);
                const rowData = row.original;
                return (
                  <tr {...row.getRowProps()} className="hover:bg-slate-800">
                    {row.cells.map(cell => (
                      <td {...cell.getCellProps()} className="px-4 py-3">
                        {cell.render('Cell')}
                      </td>
                    ))}
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
      {/* Modals */}
      {modal === 'add' && (
        <Modal title="➕ Ajouter du stock" onClose={() => setModal(null)}>
          <StockForm produits={produits} entrepots={entrepots} type="add"
                     onSubmit={handleOp(addStock, 'Stock ajouté !')} />
        </Modal>
      )}
      {modal === 'remove' && (
        <Modal title="➖ Retirer du stock" onClose={() => setModal(null)}>
          <StockForm produits={produits} entrepots={entrepots} type="remove"
                     onSubmit={handleOp(removeStock, 'Stock retiré !')} />
        </Modal>
      )}
      {modal === 'transfer' && (
        <Modal title="🔄 Transférer du stock" onClose={() => setModal(null)}>
          <StockForm produits={produits} entrepots={entrepots} type="transfer"
                     onSubmit={handleOp(transferStock, 'Transfert effectué !')} />
        </Modal>
      )}
    </div>
  );
}
